func newCmdAndroidLocationINetInitiatedListener_SendNiResponse() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "send-ni-response",
		Short: "Call SendNiResponse(notifId int32, userResponse int32) -> bool",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.location.INetInitiatedListener")
			}
			if err != nil {
				return err
			}

			svcProxy := location.NewNetInitiatedListenerProxy(svc)

			flagNotifId, err := cmd.Flags().GetInt32("notifId")
			if err != nil {
				return fmt.Errorf("reading flag notifId: %w", err)
			}

			flagUserResponse, err := cmd.Flags().GetInt32("userResponse")
			if err != nil {
				return fmt.Errorf("reading flag userResponse: %w", err)
			}

			result, err := svcProxy.SendNiResponse(ctx, flagNotifId, flagUserResponse)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("result", result)
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().Int32("notifId", 0, "notifId (int32)")
	_ = cmd.MarkFlagRequired("notifId")
	cmd.Flags().Int32("userResponse", 0, "userResponse (int32)")
	_ = cmd.MarkFlagRequired("userResponse")

	return cmd
}
